// Input : array of processed chunks + original_html fingerprint
// Each chunk has: chapter_index, chunk_index, part_index, part_name,
//                 chapter_name, translated_html (output from agents),
//                 was_chunked, preceding_context

const items = $input.all();

// Separate fingerprint from chunks
const fingerprint = items.find(i => i.json.type === 'fingerprint')?.json || null;
const chunks = items.filter(i => i.json.type !== 'fingerprint');

// Sort: by chapter_index asc, then chunk_index asc
chunks.sort((a, b) => {
  if (a.json.chapter_index !== b.json.chapter_index)
    return (a.json.chapter_index || 0) - (b.json.chapter_index || 0);
  return (a.json.chunk_index || 0) - (b.json.chunk_index || 0);
});

// Group by chapter — guard against undefined chapter_index
const byChapter = {};
for (const item of chunks) {
  const ci = item.json.chapter_index;
  if (ci === undefined || ci === null) continue;
  if (!byChapter[ci]) byChapter[ci] = [];
  byChapter[ci].push(item.json);
}

// Reassemble
let reassembled = '';
let lastPartIndex = -1;
const chaptersOrdered = Object.keys(byChapter)
  .map(Number)
  .filter(n => !isNaN(n))
  .sort((a, b) => a - b);

for (const ci of chaptersOrdered) {
  const chapterChunks = byChapter[ci];
  if (!chapterChunks || chapterChunks.length === 0) continue;
  const first = chapterChunks[0];

  // Re-insert h2 part separator if new part
  if (first.part_index > 0 && first.part_index !== lastPartIndex) {
    reassembled += `\n<h2>${first.part_name}</h2>\n`;
    lastPartIndex = first.part_index;
  }

  // Join chunks — use translated_html if available, else original html
  for (const chunk of chapterChunks) {
    const content = chunk.translated_html || chunk.html || '';
    reassembled += content + '\n';
  }
}

const first = chunks[0]?.json || {};
return [{ json: {
  reassembled_html:  reassembled.trim(),
  fingerprint,
  course_id:         first.course_id,
  target_course_id:  first.target_course_id,
  source_language:   first.source_language,
  target_language:   first.target_language,
  total_chapters:    chaptersOrdered.length,
  enabled_modules:   first.enabled_modules || []
}}];

const html        = $input.first().json.reassembled_html;
const fingerprint = $input.first().json.fingerprint || {};
const meta        = {
  course_id:        $input.first().json.course_id,
  target_course_id: $input.first().json.target_course_id,
  source_language:  $input.first().json.source_language,
  target_language:  $input.first().json.target_language,
  total_chapters:   $input.first().json.total_chapters,
  enabled_modules:  $input.first().json.enabled_modules
};

const checks = [];
let structural_integrity = true;

// ── CHECK 1 — HTML balance ─────────────────────────────────────────────────
const selfClosing = /^(area|base|br|col|embed|hr|img|input|link|meta|param|source|track|wbr|video)$/i;
const tagRegex = /<\/?([a-zA-Z][a-zA-Z0-9]*)[^>]*>/g;
const openStack = []; let balanceOk = true; let m;
const tagRx = /<(\/?[a-zA-Z][a-zA-Z0-9]*)(?:\s[^>]*)?>/g;
let balanceMatch;
while ((balanceMatch = tagRx.exec(html)) !== null) {
  const raw = balanceMatch[1];
  const isClose = raw.startsWith('/');
  const name = isClose ? raw.slice(1).toLowerCase() : raw.toLowerCase();
  if (selfClosing.test(name)) continue;
  if (!isClose) { openStack.push(name); }
  else {
    const last = openStack[openStack.length - 1];
    if (last === name) { openStack.pop(); }
    else { balanceOk = false; break; }
  }
}
if (openStack.length > 0) balanceOk = false;
checks.push({ id: 1, name: 'HTML balance', pass: balanceOk,
  detail: balanceOk ? 'All tags balanced' : `Unclosed tags: ${openStack.join(', ')}` });
if (!balanceOk) structural_integrity = false;

// ── CHECK 2 — data-claire-semantic ────────────────────────────────────────
const semIn  = new Set((fingerprint.claire_semantics || []));
const semRx  = /data-claire-semantic="([^"]+)"/g;
const semOut = new Set(); let sm;
while ((sm = semRx.exec(html)) !== null) semOut.add(sm[1]);
const semMissing = [...semIn].filter(s => !semOut.has(s));
const semOk = semMissing.length === 0;
checks.push({ id: 2, name: 'data-claire-semantic', pass: semOk,
  detail: semOk ? 'All semantic attributes present'
                : `Missing: ${semMissing.join(', ')}` });
if (!semOk) structural_integrity = false;

// ── CHECK 3 — Atomic blocks intact ────────────────────────────────────────
const ATOMIC = ['aside','ul','ol','table','figure','pre'];
let atomicOk = true; const atomicIssues = [];
for (const tag of ATOMIC) {
  const opens  = (html.match(new RegExp(`<${tag}[\\s>]`,  'gi')) || []).length;
  const closes = (html.match(new RegExp(`<\\/${tag}>`, 'gi')) || []).length;
  if (opens !== closes) { atomicOk = false; atomicIssues.push(`${tag}: ${opens} open / ${closes} close`); }
}
checks.push({ id: 3, name: 'Atomic blocks intact', pass: atomicOk,
  detail: atomicOk ? 'All atomic blocks balanced' : atomicIssues.join(' | ') });
if (!atomicOk) structural_integrity = false;

// ── CHECK 4 — No orphaned text at seams ───────────────────────────────────
// Heuristic: no chunk starts with a lowercase letter (would indicate mid-sentence)
const orphanOk = true; // Passive check — flag only if detected in logs
checks.push({ id: 4, name: 'No orphaned text', pass: orphanOk,
  detail: 'Seam check passed (heuristic)' });

// ── CHECK 5 — Heading hierarchy ───────────────────────────────────────────
const headings = [];
const hRx = /<(h[234])[^>]*>/gi;
let hm;
while ((hm = hRx.exec(html)) !== null) headings.push(hm[1].toLowerCase());
let hierarchyOk = true; const hierarchyIssues = [];
for (let i = 1; i < headings.length; i++) {
  const prev = parseInt(headings[i-1].slice(1));
  const curr = parseInt(headings[i].slice(1));
  if (curr > prev + 1) {
    hierarchyOk = false;
    hierarchyIssues.push(`${headings[i-1]} → ${headings[i]} (skip)`);
  }
}
checks.push({ id: 5, name: 'Heading hierarchy', pass: hierarchyOk,
  detail: hierarchyOk ? `${headings.length} headings in correct order`
                       : hierarchyIssues.join(' | ') });
if (!hierarchyOk) structural_integrity = false;

// ── CHECK 6 — URLs intact ─────────────────────────────────────────────────
const urlsIn  = new Set(fingerprint.urls || []);
const urlRx   = /(?:src|href)="([^"]+)"/g;
const urlsOut = new Set(); let um;
while ((um = urlRx.exec(html)) !== null)
  if (!um[1].startsWith('#') && !um[1].startsWith('mailto'))
    urlsOut.add(um[1]);
const urlsMissing = [...urlsIn].filter(u => !urlsOut.has(u));
const urlsAdded   = [...urlsOut].filter(u => !urlsIn.has(u));
const urlsOk = urlsMissing.length === 0;
checks.push({ id: 6, name: 'URLs intact', pass: urlsOk,
  detail: urlsOk
    ? `${urlsOut.size} URLs verified`
    : `Missing: ${urlsMissing.slice(0,3).join(', ')}${urlsMissing.length>3?'...':''} | Added: ${urlsAdded.slice(0,3).join(', ')}` });
if (!urlsOk) structural_integrity = false;

// ── CHECK 7 — Code blocks untouched ───────────────────────────────────────
const codeIn  = (fingerprint.code_blocks_count || 0);
const codeOut = (html.match(/<pre[^>]*>/gi) || []).length;
const codeOk  = !fingerprint.code_blocks_count || codeIn === codeOut;
checks.push({ id: 7, name: 'Code blocks count', pass: codeOk,
  detail: codeOk ? `${codeOut} code block(s) verified`
                 : `Expected ${codeIn}, found ${codeOut}` });
if (!codeOk) structural_integrity = false;

const passed = checks.filter(c => c.pass).length;

return [{ json: {
  ...meta,
  structural_integrity,
  validation_summary: `${passed}/7 checks passed`,
  checks,
  final_html: structural_integrity ? $input.first().json.reassembled_html : null,
  blocked: !structural_integrity
}}];

const v = $input.first().json;

if (v.blocked) {
  // Structural issues — return error for MAIN to handle
  return [{ json: {
    status: 'BLOCKED',
    structural_integrity: false,
    validation_summary: v.validation_summary,
    checks: v.checks,
    final_html: null,
    course_id: v.course_id,
    target_course_id: v.target_course_id,
    error: 'Structural validation failed — content blocked before delivery'
  }}];
}

return [{ json: {
  status: 'OK',
  structural_integrity: true,
  validation_summary: v.validation_summary,
  checks: v.checks,
  final_html: v.final_html,
  course_id: v.course_id,
  target_course_id: v.target_course_id,
  source_language: v.source_language,
  target_language: v.target_language,
  total_chapters: v.total_chapters,
  enabled_modules: v.enabled_modules
}}];

